INSERT INTO `consultants` VALUES
(1, 'bora-isik', 'Bora Işık', 'Growth Marketing & Fractional CMO Uzmanı', 'B2B ve B2C pazarlarında 15+ yıl deneyimle büyüme stratejisi, pazarlama organizasyonu ve satış-pazarlama entegrasyonu konularında danışmanlık hizmeti vermektedir. Fintech, ödeme sistemleri, SaaS ve kurumsal sektörlerde ekipleri ve ajansları yönlendirmiştir.', 'https://egirisim.com/wp-content/uploads/2019/12/bora-isik-scaled-e1576484683642-1068x580.jpg', '5.0', 24, 'fintech', 'odeme-sistemleri', 'teknoloji-yazilim', 'b2b', 'filo-kiralama', 'uretim', 'ic-tasarim', 'enerji', 1, '2026-03-19 04:58:58.000', '2026-03-19 06:31:24.000');
