(2, 'gtm-growth', 'hizmetlerimiz/go-to-market-stratejisi/growth', 'services/go-to-market-strategy/growth', 'Go To Market - Growth', 'Go To Market - Growth', 'Gelişmiş bir dijital, içerik ve pazarlama otomasyonu, satış stratejisi ile büyümeyi hedefleyen orta ölçekli işletmeler için ideal.', '360-degree digital presence management.', '14900.00', 'USD', 'service', 1, '2026-02-03 14:43:01.000', '2026-02-25 04:57:27.000', 'service', NULL, NULL, NULL, NULL, NULL, 'Integrated Digital Marketing | khilonfast', 'Complete digital marketing solutions.', NULL, '/images/hizmetlerimiz/go-to-market-stratejisi/hero.png', NULL, NULL, NULL, '/images/hizmetlerimiz/go-to-market-stratejisi/hero.png'),
